#include <stdio.h>
#include <string.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        char s[n + 1];
        scanf("%s", s);
        for (int i = 0; i < n; i++) {
            if (s[i] != 'a' && s[i] != 'b' && k > 0) {
                s[i] = 'a';
                k--;
            }
        }
        printf("%s\n", s);
    }
    return 0;
}

