const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let [n, k] = input[j * 2].split(' ').map(num => parseInt(num));
            let s = input[j * 2 + 1];
            for (let i = 0; i < n; i++) {
                if (s[i] !== 'a' && s[i] !== 'b' && k > 0) {
                    s = s.substring(0, i) + 'a' + s.substring(i + 1);
                    k--;
                }
            }
            console.log(s);
        }
    }
});

